function minDays(bloomDay, m, k) {
    if (m * k > bloomDay.length) return -1;

    let maxVal = Math.max(...bloomDay);
    let low = 1, high = maxVal, ans = -1;

    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        let bouquets = 0, flowers = 0;

        for (let bloom of bloomDay) {
            if (bloom <= mid) {
                flowers++;
                if (flowers === k) {
                    bouquets++;
                    flowers = 0;
                }
            } else {
                flowers = 0;
            }
        }

        if (bouquets >= m) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return ans;
}
